value.Email:
={{
(
  $node["ApexVerify - Email Address Verification"].json.status !== 'ok'
    ? '🚨'
    : $node["ApexVerify - Email Address Verification"].json.verification_result.valid
      ? '✅'
      : $node["ApexVerify - Email Address Verification"].json.verification_result.unknown
        ? '❓'
        : $node["ApexVerify - Email Address Verification"].json.verification_result.wrong
          ? '❌'
          : '🚨'
) + ' ||| ' + $node["Google Sheets Trigger"].json.Email
}}

